def signal(text):
    return bool(re.search(r'(?i)ignore previous instructions|system prompt', text))

def request_for(text):
    return {
        'untrusted_document': text,
        'allowed_tools': [],
        'max_output_chars': 160,
        'requires_human_approval': True,
    }

request = request_for(s)
